"""
MKT Original Language Commentary — John chapter 11
Run: python3 scripts/zc-original-john-11-11.py

Source data used:
- data/interlinear/john.json (chapter 11 tokens)
- data/translation/glossary-greek.json (semantic ranges)
- data/translation/notes/john.json (translation reasoning)
- data/translation/draft/mediating/john.json (MKT text for reference)

Key decisions in this range:
- "the Evangelist" continues as authorial designation throughout
- φιλέω vs ἀγαπάω: the sisters' message (v3) uses φιλεῖς (friendship love);
  the Evangelist's summary (v5) uses ἠγάπα (ἀγαπάω, covenant love); bystanders
  (v36) use ἐφίλει again — the shift is deliberate and noted
- ἐμβριμάομαι (vv33, 38): rendered "deeply moved" in most translations but
  the verb carries the force of suppressed anger, indignation, or intense groaning —
  it is far stronger than mere emotion; both occurrences noted
- ἐδάκρυσεν (v35): different from κλαίω (G2799, the loud mourning-weep of Mary
  and the crowd in v33) — quieter, tears rather than wailing; noted
- τετραήμερος (four days, v17/v39): the Jewish belief that the soul lingered
  near the body for three days before permanently departing makes four days the
  point of absolute, irreversible death — noted at v17
- συμφέρει (v50): Caiaphas's political term "expedient/advantageous" — the
  Evangelist's irony operates at the lexical level; the word chosen by the high
  priest for cold calculation is the same the narrator uses for theological
  substitutionary import
- τὰ τέκνα τοῦ θεοῦ τὰ διεσκορπισμένα (v52): uses the same διασκορπίζω
  root as 10:12 (wolf scattering the sheep) — the gathering of scattered children
  is the reversal of the scattering
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


JOHN = {
  "11": {
    "1": '<p><strong>ἀσθενῶν</strong> (G770, present participle) — "sick/weakening." The participial form marks an ongoing condition rather than a sudden crisis. <strong>Λάζαρος ἀπὸ Βηθανίας</strong> — the name Lazarus is the Hellenized form of the Hebrew <em>Elʿāzār</em> (אֶלְעָזָר, "God has helped"). The naming at the chapter\'s opening is a Johannine technique: the figure who will be raised is named before the crisis is described, so the reader knows who is at stake. Bethany is identified as the village of Mary and Martha — a detail that presupposes the reader knows these women, suggesting the traditions about them were already widely circulated when the Evangelist wrote.</p>',

    "2": '<p><strong>ἦν δὲ Μαριὰμ ἡ ἀλείψασα τὸν κύριον μύρῳ</strong> — "Now it was Mary who had anointed the Lord with ointment." The aorist <em>aleipsasa</em> (G218, anointing) refers proleptically to the event the Evangelist will narrate in chapter 12. The Evangelist inserts this identification here — before telling the story — presumably because Mary was already well-known in the community as "the one who anointed the Lord." <strong>ἐκμάξασα τοὺς πόδας αὐτοῦ ταῖς θριξὶν αὐτῆς</strong> — "and wiped his feet with her hair" — the detail specifies which Mary is meant; the anointing-with-hair is the identifying mark. Its placement here gives the subsequent conversation (especially Jesus\'s love for this household) a concrete, intimate context.</p>',

    "3": '<p><strong>ἀπέστειλαν</strong> (aorist, G649) — the sisters "sent" the message, a deliberate act of reaching out rather than a casual report. The message itself is notable for what it does not ask: there is no request for Jesus to come, only the statement of the situation. <strong>κύριε, ἴδε ὃν φιλεῖς ἀσθενεῖ</strong> — "Lord, behold, he whom you love is sick." The verb <em>phileis</em> is G5368 (<em>phileō</em>), the love of personal affection and friendship — not G25 (<em>agapaō</em>). The sisters appeal to Jesus\'s personal bond with their brother. The Evangelist will use the weightier <em>agapaō</em> in his own narrative summary (v5), but the sisters\' word choice reflects the intimacy of friendship rather than the covenantal dimension.</p>',

    "4": '<p><strong>αὕτη ἡ ἀσθένεια οὐκ ἔστιν πρὸς θάνατον</strong> — "this sickness is not toward death." The Greek idiom <em>pros thanaton</em> means oriented toward death as its destination or end point — not that Lazarus won\'t die, but that death is not the final horizon of this sickness. The phrase deliberately echoes 1 John 5:16–17 ("sin not toward death"). <strong>ἀλλ᾽ ὑπὲρ τῆς δόξης τοῦ θεοῦ</strong> — "but for the glory of God." <em>Hyper</em> (G5228) with the genitive: "on behalf of" or "for the sake of." The goal clause that follows — <strong>ἵνα δοξασθῇ ὁ υἱὸς τοῦ θεοῦ δι᾽ αὐτῆς</strong> — "so that the Son of God may be glorified through it" — uses the same verb (<em>doxazō</em>, G1392) the Evangelist uses throughout for Christ\'s glorification through crucifixion and resurrection (7:39; 12:16, 23; 13:31–32). The raising of Lazarus is already framed within the cross-and-resurrection trajectory.</p>',

    "5": '<p><strong>ἠγάπα δὲ ὁ Ἰησοῦς τὴν Μάρθαν καὶ τὴν ἀδελφὴν αὐτῆς καὶ τὸν Λάζαρον</strong> — "now Jesus loved Martha and her sister and Lazarus." The verb here is <em>agapaō</em> (G25, imperfect — an ongoing, settled love), not the <em>phileō</em> of the sisters\' message (v3). The Evangelist\'s deliberate shift to <em>agapaō</em> for his own summary broadens the love from friendship (<em>phileō</em>) to covenant-sustaining commitment. The imperfect <em>ēgapa</em> marks this as the enduring background condition against which the two-day delay of v6 will be read: the delay is not indifference.</p>',

    "6": '<p><strong>ὡς οὖν ἤκουσεν ὅτι ἀσθενεῖ, τότε μὲν ἔμεινεν ἐν ᾧ ἦν τόπῳ δύο ἡμέρας</strong> — "when therefore he heard that he was sick, at that time he remained in the place where he was two days." The word <em>oun</em> (G3767, "therefore/then") immediately after "Jesus loved them" makes the delay a consequence of the love, not its contradiction. The deliberate two-day wait — while a friend lies dying — is the Johannine pattern of divine timing subordinating human urgency to a larger design (cf. 2:4; 7:6–8). <em>Emeinen</em> (G3306, "remained/stayed") is the Evangelist\'s verb of purposeful dwelling, not passive inaction.</p>',

    "7": '<p><strong>μετὰ τοῦτο λέγει τοῖς μαθηταῖς</strong> — "after this he says to the disciples." The narrative temporal marker <em>meta touto</em> ("after this/these things") is one of the Evangelist\'s characteristic connectors between units (cf. 2:12; 3:22; 5:1; 6:1; 7:1). <strong>ἄγωμεν εἰς τὴν Ἰουδαίαν πάλιν</strong> — "let us go into Judea again." The hortatory subjunctive <em>agōmen</em> (G71) is Jesus issuing a summons, not proposing a discussion. The word <em>palin</em> ("again") is significant: the disciples heard "again" and immediately remembered the stones (v8). Return to Judea is return to danger.</p>',

    "8": '<p><strong>νῦν ἐζήτουν σε λιθάσαι οἱ Ἰουδαῖοι</strong> — "the Jews were just now seeking to stone you." The imperfect <em>ezētoun</em> (G2212) frames the stoning as an ongoing, recent threat, not a past incident resolved. The adverb <em>nyn</em> ("now/just now") makes it immediate. <strong>πάλιν ὑπάγεις ἐκεῖ;</strong> — "you are going back there again?" The second <em>palin</em> in two verses: the disciples cannot understand the pattern of deliberate return into danger. Their objection is practically reasonable and theologically opaque — they do not yet see what Jesus sees.</p>',

    "9": '<p><strong>οὐχὶ δώδεκα ὧραί εἰσιν τῆς ἡμέρας;</strong> — "Are there not twelve hours of the day?" The rhetorical question about the twelve-hour day draws on common knowledge of the Jewish and Greco-Roman day divided into twelve equal hours (dawn to dusk). <strong>ἐὰν τις περιπατῇ ἐν τῇ ἡμέρᾳ, οὐ προσκόπτει</strong> — "if anyone walks in the day, he does not stumble." <em>Proskoptō</em> (G4350) — to strike against, stumble. The reason given: <strong>ὅτι τὸ φῶς τοῦ κόσμου τούτου βλέπει</strong> — "because he sees the light of this world." The walking-in-light/darkness metaphor from chapters 8–9 is reactivated: Jesus operates within the light of his appointed time (cf. 9:4–5). His movement into danger is calibrated walking in daylight, not reckless stumbling in darkness.</p>',

    "10": '<p><strong>ἐὰν δέ τις περιπατῇ ἐν τῇ νυκτί, προσκόπτει</strong> — "but if anyone walks in the night, he stumbles." The contrast completes the antithetical parallel of v9. <strong>ὅτι τὸ φῶς οὐκ ἔστιν ἐν αὐτῷ</strong> — "because the light is not in him." The phrasing shifts from external light (v9: "the light of this world") to internal light: the one who has no light within stumbles regardless of external conditions. The Evangelist uses the same <em>en autō</em> construction as in 1:4 ("in him was life, and the life was the light of humanity"). The disciples\' failure to understand Jesus\'s movement is itself an instance of stumbling for lack of the light within.</p>',

    "11": '<p><strong>Λάζαρος ὁ φίλος ἡμῶν κεκοίμηται</strong> — "Lazarus our friend has fallen asleep." <em>Kekoimētai</em> (G2837, perfect passive) — "has fallen asleep and remains in that state." The perfect tense marks the sleep as a present condition with a completed onset. The sleep euphemism for death was widely used in both Jewish and Greco-Roman usage (cf. Ps 13:3 LXX; 1 Thess 4:13–15), but the Evangelist will immediately show that the disciples take the word at face value, forcing Jesus to speak plainly. <strong>ἵνα ἐξυπνίσω αὐτόν</strong> — "that I may wake him." <em>Exypnizō</em> (G1852) — to rouse from sleep, wake up. The purpose clause frames the journey as a mission of awakening, not a journey to mourn.</p>',

    "12": '<p><strong>κύριε, εἰ κεκοίμηται σωθήσεται</strong> — "Lord, if he has fallen asleep, he will be saved/will get better." <em>Sōthēsetai</em> (G4982, future passive of <em>sōzō</em>) in the disciples\' mouth means "he will recover/get well" — they take <em>koimasthai</em> as literal sleep and conclude that sleep indicates recovery rather than crisis. But <em>sōzō</em> in the Evangelist\'s register typically means far more: rescue, deliverance, salvation. The disciples\' mundane use of the word anticipates what the raising will accomplish at a deeper level than they intend.</p>',

    "13": '<p><strong>εἰρήκει δὲ ὁ Ἰησοῦς περὶ τοῦ θανάτου αὐτοῦ</strong> — "but Jesus had spoken of his death." The pluperfect <em>eirēkei</em> (G2046) — "he had spoken" — positions the narrator\'s clarification as filling in what was latent in Jesus\'s words all along. <strong>ἐκεῖνοι δὲ ἔδοξαν ὅτι περὶ τῆς κοιμήσεως τοῦ ὕπνου λέγει</strong> — "but they thought that he was speaking of the repose of sleep." The noun <em>koimēsis</em> (G2838) — "taking of rest, sleep" — the disciples interpret the metaphor in the only register they can access. This misunderstanding is the Evangelist\'s technique of ironic miscommunication that illuminates what the crowd or disciples cannot yet see: Lazarus is not sleeping but dead, and Jesus is going to reverse what "dead" means.</p>',

    "14": '<p><strong>τότε οὖν εἶπεν αὐτοῖς ὁ Ἰησοῦς παρρησίᾳ</strong> — "then therefore Jesus said to them plainly." <em>Parrēsia</em> (G3954, adverb) — "with openness, frankly, without figure." The same word Martha will use in v57 when people expect Jesus to speak plainly, and the same word the disciples request in 16:25, 29. Jesus sets aside the sleep metaphor entirely. <strong>Λάζαρος ἀπέθανεν</strong> — "Lazarus is dead." The aorist <em>apethanen</em> (G599) is blunt: completed action, unambiguous death. After two-day delay, after indirect speech about sleep, the plain word falls without elaboration.</p>',

    "15": '<p><strong>χαίρω δι᾽ ὑμᾶς, ἵνα πιστεύσητε, ὅτι οὐκ ἤμην ἐκεῖ</strong> — "and I am glad for your sakes that I was not there, so that you may believe." <em>Chairō</em> (G5463) — joy, gladness. Jesus is glad he was absent — not because he is indifferent to the suffering, but because the death creates the condition for a sign that will produce deeper faith than a healing would have. The purpose clause <em>hina pisteusēte</em> (G4100, aorist subjunctive) frames the entire event as a faith-catalysis. The disciples already believe in some sense (1:49; 6:68); what they are about to believe will be at a different depth. <strong>ἀλλὰ ἄγωμεν πρὸς αὐτόν</strong> — "but let us go to him." The hortatory subjunctive again — Jesus leads into danger.</p>',

    "16": '<p><strong>Θωμᾶς ὁ λεγόμενος Δίδυμος</strong> — "Thomas, called Didymus." The Evangelist provides the Greek equivalent: <em>Didymos</em> (G1324) = "twin." Thomas\'s name is always given with this translation note in the Fourth Gospel (11:16; 20:24; 21:2) — a feature unique to this Gospel. <strong>Ἄγωμεν καὶ ἡμεῖς ἵνα ἀποθάνωμεν μετ᾽ αὐτοῦ</strong> — "let us also go so that we may die with him." The word <em>autou</em> is ambiguous: "with him" could refer to Lazarus (dying alongside a dying friend) or Jesus (dying alongside the master who is heading to his death). The saying has the ring of courageous, if grim, loyalty. Thomas does not understand the resurrection that is coming, but he understands the danger and commits anyway — a complex portrait that prepares for his doubt in chapter 20.</p>',

    "17": '<p><strong>εὗρεν αὐτὸν τέσσαρας ἤδη ἡμέρας ἔχοντα ἐν τῷ μνημείῳ</strong> — "he found him having been four days already in the tomb." The verb <em>heuriskō</em> (G2147, "to find") is used throughout John for the moment of significant discovery. The four-day detail (<em>tetartaios</em>, G5066, in v39) is not a casual chronological note. In Second Temple Jewish belief, the soul was thought to linger near the body for three days before permanently departing; on the fourth day, irreversible decay was presumed to have begun (the <em>Leviticus Rabbah</em> tradition; cf. also the concern Martha expresses in v39). Four days is not simply "more than three" — it is the socially established threshold of final, irreversible death. The Evangelist places Jesus\'s arrival precisely here.</p>',

    "18": '<p><strong>ἦν δὲ ἡ Βηθανία ἐγγὺς τῶν Ἱεροσολύμων ὡς ἀπὸ σταδίων δεκαπέντε</strong> — "now Bethany was near Jerusalem, about fifteen stadia away." A <em>stadion</em> (G4712) is approximately 185–192 meters; fifteen stadia is roughly 1.8 miles (about 3 km). The geographical detail serves a narrative function: Jerusalem is close enough that the Jewish mourners have come out from the city (v19), and the events at Bethany will immediately reach the ears of the Pharisees (v46). The raising happens within easy report-range of the Sanhedrin.</p>',

    "19": '<p><strong>πολλοὶ δὲ ἐκ τῶν Ἰουδαίων ἐληλύθεισαν</strong> — "many of the Jews had come." The pluperfect <em>elelythisan</em> (G2064) marks their arrival as prior to Jesus\'s — they are already there when he comes. <strong>παραμυθήσωνται αὐτὰς περὶ τοῦ ἀδελφοῦ</strong> — "to console them concerning their brother." <em>Paramytheomai</em> (G3888, G3888) — to encourage, console, comfort; the word implies sustained presence alongside the grieving. Jewish mourning practices of the period included a seven-day formal mourning period (<em>shiva</em>) during which friends and community came to "sit with" the bereaved. The large crowd of mourners from Jerusalem is both a cultural reality and a narrative device: witnesses will be present for what happens next.</p>',

    "20": '<p><strong>Μάρθα μὲν οὖν ὡς ἤκουσεν ὅτι Ἰησοῦς ἔρχεται ὑπήντησεν αὐτῷ</strong> — "Martha therefore, when she heard that Jesus was coming, went to meet him." The verb <em>hypantaō</em> (G5221) — to go toward and meet someone on the way. Martha\'s immediate action to go out contrasts with Mary who "sat in the house" (<em>ēsato en tō oikō</em>). The contrast recapitulates the sisters\' characteristic patterns seen in Luke 10:38–42 without the Evangelist needing to cite them: Martha acts, Mary waits.</p>',

    "21": '<p><strong>κύριε, εἰ ἦς ὧδε οὐκ ἂν ἀπέθανεν ὁ ἀδελφός μου</strong> — "Lord, if you had been here my brother would not have died." The second-class conditional (<em>ei ēs...ouk an apethanen</em>) — "if you had been here [but you were not], he would not have died [but he did]." It is a statement of what did not happen, not a rebuke. Martha addresses it to Jesus\'s face as a fact, not an accusation. The conditional expresses faith: she believes Jesus\'s presence would have prevented the death. It does not yet express what she cannot conceive — that his absence was purposeful and that something greater than prevention is coming.</p>',

    "22": '<p><strong>ἀλλὰ καὶ νῦν οἶδα ὅτι ὅσα ἂν αἰτήσῃ τὸν θεόν, δώσει σοι ὁ θεός</strong> — "but even now I know that whatever you ask God, God will give you." The word <em>oida</em> (G1492, "I know" — the perfect with present force) marks Martha\'s confidence as settled rather than tentative. The verb <em>aitēsē</em> (G154, aorist subjunctive) — "you should ask" — frames Jesus\'s relationship with God as petitionary, which is partially accurate but misses the identity claim Jesus is about to make. Martha believes Jesus has special access to God; she is not yet prepared for "I am the resurrection."</p>',

    "23": '<p><strong>ἀναστήσεται ὁ ἀδελφός σου</strong> — "your brother will rise." The future indicative <em>anastēsetai</em> (G450) is deliberately unqualified. Jesus does not say "I will raise him" or "in a little while" — he says "he will rise," leaving the statement open enough that Martha reads it within her existing framework (resurrection at the last day, v24). The ambiguity is Johannine: the statement is true in the frame Martha hears it in, and far truer in the frame Jesus means it in. The gap between those two frames is the theological content of vv25–27.</p>',

    "24": '<p><strong>οἶδα ὅτι ἀναστήσεται ἐν τῇ ἀναστάσει ἐν τῇ ἐσχάτῃ ἡμέρᾳ</strong> — "I know that he will rise in the resurrection at the last day." Martha\'s response places "the resurrection" (<em>hē anastasis</em>, G386) at the eschatological end point: <em>tē eschatē hēmera</em> — "the last day." This is the standard Pharisaic belief: resurrection is a corporate, future, end-of-age event (cf. Dan 12:2; 2 Macc 7:9). Martha\'s theology is orthodox and correct as far as it goes. But Jesus\'s I-AM claim in v25 does not contradict Pharisaic eschatology — it relocates resurrection from a future event to a present Person. Martha knows the doctrine; she is about to meet its ground of existence.</p>',

    "25": '<p><strong>ἐγώ εἰμι ἡ ἀνάστασις καὶ ἡ ζωή</strong> — "I am the resurrection and the life." The emphatic <em>egō eimi</em> (G1473 + G1510) formula with double predicate: both nouns carry the definite article, making each a specific, exclusive identification rather than a general description. Jesus does not say "I give resurrection" or "I bring life" but "I am the resurrection… I am the life." The resurrection Martha has placed at the last day is not merely something Jesus will do; it is what Jesus is. <strong>ὁ πιστεύων εἰς ἐμέ, κἂν ἀποθάνῃ, ζήσεται</strong> — "the one who believes in me, even if he should die, will live." The present participle <em>ho pisteuōn</em> ("the one believing" — ongoing, characteristic faith) is paired with <em>kan apothanē</em> (G2579 + G599, aorist subjunctive — "even if he should die at some point"). Physical death is acknowledged as a real event, but it is no longer the final word for the one who believes.</p>',

    "26": '<p><strong>καὶ πᾶς ὁ ζῶν καὶ πιστεύων εἰς ἐμὲ οὐ μὴ ἀποθάνῃ εἰς τὸν αἰῶνα</strong> — "and everyone living and believing in me will absolutely not die forever." The double negative <em>ou mē</em> (G3756 + G3364) with the aorist subjunctive is the strongest Greek idiom for absolute negation of a future event — not merely "probably not" but "under no circumstances." <em>Eis ton aiōna</em> ("for the age/into forever") reinforces the temporal scope. V25 spoke of those who have physically died; v26 speaks of those alive who believe. Together the two verses cover the entire spectrum: whether living or dead when Christ returns, the believer does not ultimately die. <strong>πιστεύεις τοῦτο;</strong> — "do you believe this?" The direct question moves the exchange from doctrine to personal confession.</p>',

    "27": '<p><strong>ναί, κύριε, ἐγὼ πεπίστευκα ὅτι σύ εἶ ὁ Χριστὸς ὁ υἱὸς τοῦ θεοῦ ὁ εἰς τὸν κόσμον ἐρχόμενος</strong> — "Yes, Lord, I have believed that you are the Messiah, the Son of God, the one coming into the world." The perfect <em>pepistika</em> (G4100) — "I have believed and the believing stands" — is the perfect of settled, established faith. Martha\'s confession is the most complete christological statement in the Gospel up to this point, comprising three identifications: <em>ho Christos</em> (Messiah, the anointed king), <em>ho huios tou theou</em> (Son of God, the unique relational title), and <em>ho eis ton kosmon erchomenos</em> ("the one coming into the world" — the expected figure of Mal 3:1; Ps 118:26). This threefold confession occurs here, before the raising, not after — Martha confesses without yet seeing. The Evangelist structures her faith as prior to the sign, not produced by it.</p>',

    "28": '<p><strong>ἐφώνησεν Μαριὰμ τὴν ἀδελφὴν αὐτῆς λάθρᾳ</strong> — "she called her sister Mary secretly." <em>Lathra</em> (G2977) — secretly, quietly, away from others. Martha\'s deliberate summoning of Mary away from the crowd shows practical judgment: she does not want the mourners who might misunderstand or interfere. <strong>ὁ διδάσκαλος πάρεστιν καὶ φωνεῖ σε</strong> — "the Teacher is here and is calling for you." Martha addresses Mary with the title <em>ho didaskalos</em> (G1320) — "the Teacher" — the title by which Jesus was addressed by those outside the innermost circle (cf. Nicodemus in 3:2; the disciples in 13:13–14). The summoning by name is deliberate: Jesus is calling for Mary specifically.</p>',

    "29": '<p><strong>ἐκείνη δὲ ὡς ἤκουσεν ἠγέρθη ταχὺ</strong> — "when she heard, she rose quickly." The adverb <em>tachy</em> (G5036) — swiftly, quickly — marks Mary\'s immediate responsiveness to the summons. The verb <em>ēgerthē</em> (G1453, aorist passive) — literally "she was raised up." The Evangelist\'s word choice for Mary\'s arising from her seated mourning position carries an echo of the vocabulary of resurrection, though the primary sense is simply rising to her feet.</p>',

    "30": '<p><strong>οὔπω δὲ ἐληλύθει ὁ Ἰησοῦς εἰς τὴν κώμην</strong> — "now Jesus had not yet come into the village." The pluperfect <em>elelythei</em> (G2064) — had not yet arrived. He is still at the place outside the village where Martha met him. The detail is preparation for v31: the mourning crowd sees Mary leave and assumes she is going to the tomb. The Evangelist sets up the group\'s misinterpretation so that they follow her to Jesus accidentally, becoming witnesses to what follows.</p>',

    "31": '<p><strong>νομίσαντες ὅτι ὑπάγει εἰς τὸ μνημεῖον ἵνα κλαύσῃ ἐκεῖ</strong> — "thinking that she was going to the tomb to weep there." <em>Nomizō</em> (G3543, aorist participle) — to suppose, assume, think. Their assumption is culturally plausible: Mary has risen quickly from mourning and is moving with purpose. The verb <em>klausē</em> (G2799, aorist subjunctive of <em>klaiō</em>) — to weep, wail. The mourning-cry is the same verb used in v33 for the weeping of Mary and the Jews that Jesus witnesses. Their misunderstanding is not foolish — they have no reason to think otherwise. But it means they follow her to the place of miracle as accidental witnesses, drawn by the expectation of continued mourning.</p>',

    "32": '<p><strong>ἔπεσεν αὐτοῦ πρὸς τοὺς πόδας</strong> — "she fell at his feet." The verb <em>piptō</em> (G4098, aorist) — to fall, fall prostrate. The posture of falling at feet in the Greco-Roman and Jewish world signals deep submission, supplication, or worship (cf. 9:38 where the healed man "worshiped" Jesus). Mary\'s posture is simultaneously the posture of grief and the posture of a suppliant before one with power to act. <strong>κύριε, εἰ ἦς ὧδε οὐκ ἄν μου ἀπέθανεν ὁ ἀδελφός</strong> — Mary\'s words are identical to Martha\'s in v21, with only the pronoun order varied (<em>mou</em> placed before <em>adelphos</em>). The two sisters arrive at exactly the same statement of belief, expressed separately. Their shared faith formulation — Jesus\'s presence would have prevented death — is the unanimous testimony of the household.</p>',

    "33": '<p><strong>ὡς εἶδεν αὐτὴν κλαίουσαν καὶ τοὺς συνελθόντας αὐτῇ Ἰουδαίους κλαίοντας</strong> — "when he saw her weeping and the Jews who had come with her weeping." The verb <em>klaiō</em> (G2799, G2799) — loud weeping, wailing — is used for the mourning of Mary and the crowd. <strong>ἐνεβριμήσατο τῷ πνεύματι καὶ ἐτάραξεν ἑαυτόν</strong> — "he was deeply moved in spirit and troubled himself." <em>Embrimaomai</em> (G1690) is not a gentle emotion word. Its primary sense in Greek is to snort with anger, to be indignant, to groan with strong feeling — used elsewhere in the NT for Jesus rebuking a leper (Mark 1:43) and for the stern admonition not to tell (Mark 14:5). The word carries force close to controlled outrage or deep indignation. <em>Tarassō</em> (G5015) — to stir up, disturb, trouble — used in John for the stirring of the Bethesda pool (5:4, 7) and for Jesus\'s troubled spirit before the cross (12:27; 13:21). Jesus is not merely sorrowful: he is shaken in a way the text deliberately intensifies.</p>',

    "34": '<p><strong>ποῦ τεθείκατε αὐτόν;</strong> — "where have you laid him?" <em>Tithēmi</em> (G5087, perfect — "where have you placed him and he remains placed") — the same verb Jesus uses in chapter 10 for "laying down" his life. Here it is the bystanders who have "laid" Lazarus in the tomb. The question is not for information — as v41–42 will make clear, Jesus already knows what he is about to do — but it draws the crowd along as participants in the scene, witnesses who will lead him to the very spot.</p>',

    "35": '<p><strong>ἐδάκρυσεν ὁ Ἰησοῦς</strong> — "Jesus wept." This is the shortest verse in the New Testament in Greek: two words. The verb <em>dakryō</em> (G1145) is distinct from <em>klaiō</em> (G2799), the word used for Mary\'s and the crowd\'s weeping in v33. <em>Klaiō</em> is loud mourning-wailing; <em>dakryō</em> is the shedding of tears, quieter and more restrained. The crowd\'s grief is open and vocal; Jesus\'s is inward and visible only in tears. The Evangelist reports it without commentary. The theological freight is considerable: the one who just declared himself "the resurrection and the life" stands before a tomb in tears. His knowledge of what he is about to do does not prevent the grief. Both are simultaneously true.</p>',

    "36": '<p><strong>ἴδε πῶς ἐφίλει αὐτόν</strong> — "see how he loved him." The bystanders read the tears as proof of love. The verb is <em>phileō</em> (G5368, imperfect — "he used to love him/he loved him") — the same word the sisters used in v3 for the love they appealed to. The crowd names what they see: a man weeping for a friend he loved. Their reading is not wrong. But it is incomplete: the grief is the full, felt grief of one who loves; it does not cancel the power he is about to exercise.</p>',

    "37": '<p><strong>οὐκ ἐδύνατο οὗτος ὁ ἀνοίξας τοὺς ὀφθαλμοὺς τοῦ τυφλοῦ ποιῆσαι ἵνα καὶ οὗτος μὴ ἀποθάνῃ;</strong> — "Could not this man who opened the eyes of the blind have caused even this man not to die?" The rhetorical question links back to chapter 9 — the healing of the blind man is the bystanders\' point of reference for Jesus\'s capacity to act. The implicit logic is: if he could do that, why not this? The question is theologically sharper than it appears: they are pointing toward the right conclusion (he had the power) while implicitly charging failure or absence. What they cannot conceive is that the failure to prevent the death was the design of the sign, not a gap in his power.</p>',

    "38": '<p><strong>Ἰησοῦς οὖν πάλιν ἐμβριμώμενος ἐν ἑαυτῷ</strong> — "Jesus therefore again groaning/deeply moved within himself." The Evangelist repeats <em>embrimaomai</em> (G1690) from v33, now as a present participle — the intense emotion is ongoing as Jesus approaches the tomb. <em>Palin</em> ("again") marks the recurrence of the same state, intensified by proximity to the tomb. <strong>ἔρχεται εἰς τὸ μνημεῖον· ἦν δὲ σπήλαιον καὶ λίθος ἐπέκειτο ἐπ᾽ αὐτῷ</strong> — "he comes to the tomb; it was a cave and a stone was lying against it." The description matches the tomb of Jesus in 19:41–20:1: a cave, a stone. The parallel is not incidental — the Evangelist shapes the Lazarus narrative as a precursor to the resurrection narrative, using the same topographical and physical details.</p>',

    "39": '<p><strong>αἴρατε τὸν λίθον</strong> — "take away the stone." The aorist imperative <em>arate</em> (G142) — a direct command. Jesus does not move the stone himself; he involves those present. Martha\'s objection follows immediately: <strong>κύριε, ἤδη ὄζει· τετραήμερος γάρ ἐστιν</strong> — "Lord, by now there is an odor, for he has been four days." <em>Ozō</em> (G3605, present) — "to smell, stink." The objection is not a failure of faith — Martha has just confessed Jesus as Messiah and Son of God — but an eruption of physical realism. The four-day detail (<em>tetarteaios</em>, G5066) re-emphasizes the burial datum of v17. Martha is saying: the body is past the point of recovery. The objection makes the miracle that follows more vivid, not less. There is no ambiguity about what state Lazarus is in.</p>',

    "40": '<p><strong>οὐκ εἶπόν σοι ὅτι ἐὰν πιστεύσῃς ὄψῃ τὴν δόξαν τοῦ θεοῦ;</strong> — "Did I not tell you that if you believe, you will see the glory of God?" The question refers back not to a word spoken in this chapter directly, but to the message of v4 (the sickness is for God\'s glory) and the encounter of vv25–26 (faith and life). <em>Pisteusēs</em> (aorist subjunctive of <em>pisteuō</em>) — the believing is the condition; <em>opsē</em> (G3700, future middle — "you will see") is the consequence. The sequence is faith → sight, not sight → faith. Martha must take the stone away before she sees the glory. The Johannine reversal of the usual order is a consistent pattern (cf. 20:29: "blessed are those who have not seen and have believed").</p>',

    "41": '<p><strong>ἦρεν οὖν τὸν λίθον</strong> — "so they took away the stone." The obedience is reported simply, without further comment on Martha\'s hesitation. <strong>Ἰησοῦς δὲ ἦρεν τοὺς ὀφθαλμοὺς ἄνω</strong> — "Jesus lifted his eyes upward." The gesture of lifting the eyes before prayer is a physical posture of prayer in Jewish practice (cf. Ps 121:1; John 17:1). <strong>πάτερ, εὐχαριστῶ σοι ὅτι ἤκουσάς μου</strong> — "Father, I thank you that you have heard me." The prayer is thanksgiving, not petition. The hearing is in the past tense (<em>ēkousas</em>, G191, aorist) — the Father has already granted the request. This is prayer reported as already-answered, which frames the raising as the execution of a divine decision previously made, not a request about to be made.</p>',

    "42": '<p><strong>ἐγὼ δὲ ᾔδειν ὅτι πάντοτέ μου ἀκούεις</strong> — "and I knew that you always hear me." The pluperfect form <em>ēdein</em> (G1492, "I had known and knew") marks the knowledge as prior and ongoing. <strong>ἀλλὰ διὰ τὸν ὄχλον τὸν περιεστῶτα εἶπον</strong> — "but because of the crowd standing around I said this." The prayer was not for Jesus\'s own benefit — he already operates within the unity of will and hearing described in 10:30 and 5:19–20 — but for the crowd\'s benefit. <strong>ἵνα πιστεύσωσιν ὅτι σύ με ἀπέστειλας</strong> — "so that they may believe that you sent me." The goal of the public prayer is the same goal stated for the event itself in v4 and v15: faith. The sending-language (<em>apesteilan</em>, G649) is the Evangelist\'s central christological shorthand — to believe in the one God sent is to rightly orient oneself toward God.</p>',

    "43": '<p><strong>ταῦτα εἰπὼν φωνῇ μεγάλῃ ἐκραύγασεν</strong> — "having said these things, he cried out with a loud voice." <em>Kraugazō</em> (G2905, aorist) — to shout, cry out loudly. The same verb is used in 18:40 and 19:6, 15 for the crowd crying out for crucifixion. The contrast is stark: the same kind of voice that will be raised against Jesus is here raised to give life. <strong>Λάζαρε, δεῦρο ἔξω</strong> — "Lazarus, come out!" The address is personal and direct: a name, and a two-word command. <em>Deuro</em> (G1204) — "come here" — combined with <em>exō</em> (G1854) — "outside/out." The command is notable for what it is not: not a petition, not an invocation, not a formula. Jesus summons the dead man by name as a shepherd calls his own sheep (cf. 10:3: "he calls his own sheep by name").</p>',

    "44": '<p><strong>ἐξῆλθεν ὁ τεθνηκὼς δεδεμένος τοὺς πόδας καὶ τὰς χεῖρας κειρίαις</strong> — "the dead man came out, bound hand and foot with linen strips." The participle <em>ho tethnēkōs</em> (G2348, perfect — "the one who has died and remains dead") identifies the figure even as he moves: he is the dead man walking out. <em>Keiriai</em> (G2750) — burial wrappings, linen strips. The detail of the wrapped condition is both realistic (he would have been bound for burial) and preparatory: what the burial wrappings signify (death) is now worn by a walking man. <strong>λύσατε αὐτὸν καὶ ἄφετε ὑπάγειν</strong> — "loose him and let him go." Two imperatives: <em>lysate</em> (G3089, to loosen, unbind) and <em>aphete</em> (G863, to release, let go). Jesus gives life; the community participates in setting the living man free. The burial clothes must be removed by human hands — the communal dimension of restoration from death is built into the command.</p>',

    "45": '<p><strong>πολλοὶ οὖν ἐκ τῶν Ἰουδαίων οἱ ἐλθόντες πρὸς τὴν Μαριὰμ καὶ θεασάμενοι ἃ ἐποίησεν ἐπίστευσαν εἰς αὐτόν</strong> — "many therefore of the Jews who had come to Mary and had seen what he did believed in him." <em>Theaomai</em> (G2300, aorist participle) — to see, behold, witness closely. The word is more deliberate than the common <em>blepō</em>: it implies looking with attention. <em>Episteusan eis auton</em> (G4100, aorist — "believed into him") — the Johannine formula for saving faith, directed toward a person rather than merely cognitive assent to a proposition. Those who witnessed the raising believed. The Evangelist records this as the immediate response, before noting the negative reaction in v46.</p>',

    "46": '<p><strong>τινὲς δὲ ἐξ αὐτῶν ἀπῆλθον πρὸς τοὺς Φαρισαίους καὶ εἶπαν αὐτοῖς ἃ ἐποίησεν Ἰησοῦς</strong> — "but some of them went away to the Pharisees and told them what Jesus had done." The same verb <em>aperchomai</em> (G565, aorist) for departure — some go toward belief, some go away with a report. Both groups witnessed the same event (<em>ha epoiēsen Iēsous</em>, "what Jesus had done" — identical phrasing in both vv45 and 46). The sign divides: it produces faith in some and, through the report, precipitates the plot to kill Jesus. This is the Johannine pattern of krisis — the sorting that occurs when the light enters the world (3:19–21).</p>',

    "47": '<p><strong>συνήγαγον οὖν οἱ ἀρχιερεῖς καὶ οἱ Φαρισαῖοι συνέδριον</strong> — "the chief priests and the Pharisees gathered a council/Sanhedrin." <em>Sunedrion</em> (G4892) — the Sanhedrin, the ruling council of 71 members comprising chief priests, elders, and scribes. This is the formal body that will adjudicate Jesus\'s fate. <strong>τί ποιοῦμεν, ὅτι οὗτος ὁ ἄνθρωπος πολλὰ σημεῖα ποιεῖ;</strong> — "what are we doing, for this man is performing many signs?" The question is practical, not theological — they do not contest the signs. <em>Polla sēmeia poiei</em> — "performs many signs" — the concession that the miracles are real is built into the formulation of the problem.</p>',

    "48": '<p><strong>ἐὰν ἀφῶμεν αὐτὸν οὕτως, πάντες πιστεύσουσιν εἰς αὐτόν</strong> — "if we leave him alone in this way, everyone will believe in him." The conditional is third-class: a real possibility requiring action. <strong>καὶ ἐλεύσονται οἱ Ῥωμαῖοι καὶ ἀροῦσιν ἡμῶν καὶ τὸν τόπον καὶ τὸ ἔθνος</strong> — "and the Romans will come and take away both our place and our nation." The double concern — <em>topos</em> (G5117, place, often used for the Temple mount in Second Temple usage) and <em>ethnos</em> (G1484, nation) — is the Sanhedrin\'s institutional anxiety: Roman reprisal for a messianic movement. The calculation is entirely political. The irony is that precisely this outcome occurred in 70 CE, though triggered not by Jesus\'s movement but by armed revolt — and the Evangelist, writing after 70, almost certainly notes the reversal.</p>',

    "49": '<p><strong>εἷς δέ τις ἐξ αὐτῶν Καϊάφας, ἀρχιερεὺς ὢν τοῦ ἐνιαυτοῦ ἐκείνου</strong> — "but a certain one of them, Caiaphas, being high priest of that year." The repeated emphasis on "that year" (<em>tou eniautou ekeinou</em>, G1763 + G1565) in vv49, 51 is a Johannine marker: the year is significant — the year of the Passover when Jesus died. <strong>ὑμεῖς οὐκ οἴδατε οὐδέν</strong> — "you know nothing at all." The double negative (<em>ouk oidate ouden</em>) is contemptuous dismissal: Caiaphas cuts off the deliberation with a rebuke of his colleagues\' competence. His confidence is the confidence of political realism, not theological insight — and yet v51 will explain that he spoke more truly than he knew.</p>',

    "50": '<p><strong>συμφέρει ὑμῖν ἵνα εἷς ἄνθρωπος ἀποθάνῃ ὑπὲρ τοῦ λαοῦ</strong> — "it is expedient for you that one man should die on behalf of the people." <em>Sympherō</em> (G4851) — to be useful, beneficial, expedient; to be in the common interest. The verb is the language of political calculation and utilitarian ethics. <em>Hyper tou laou</em> ("on behalf of/for the sake of the people") — the preposition <em>hyper</em> is precisely the preposition Paul and the Evangelist use for substitutionary atonement (cf. John 6:51; 10:11, 15; 1 John 2:2). Caiaphas uses the atonement-language of the gospel as a coldly political justification for judicial murder. The Evangelist\'s irony is exact: the high priest\'s political formula becomes, by divine providence, a theological statement he did not intend.</p>',

    "51": '<p><strong>τοῦτο δὲ ἀφ᾽ ἑαυτοῦ οὐκ εἶπεν</strong> — "but he did not say this of his own accord." The Evangelist interrupts the narrative to explain what the reader must not miss: the words were not Caiaphas\'s own. <strong>ἀλλὰ ἀρχιερεὺς ὢν τοῦ ἐνιαυτοῦ ἐκείνου ἐπροφήτευσεν</strong> — "but being high priest of that year, he prophesied." <em>Prophēteuō</em> (G4395, aorist) — to prophesy, speak as a prophet. This is a theological claim of extraordinary force: Caiaphas, while speaking cynical political calculation, was functioning as a prophet of God. The Evangelist\'s view is that God overrode the intent of the speaker and made the office of high priest, in that particular year, the vehicle of genuine prophetic utterance. The content (<em>hoti Iēsous emellen apothnēskein hyper tou ethnous</em> — "that Jesus was about to die on behalf of the nation") is taken by the narrator as a true statement of what was about to happen.</p>',

    "52": '<p><strong>καὶ οὐχ ὑπὲρ τοῦ ἔθνους μόνον, ἀλλ᾽ ἵνα καὶ τὰ τέκνα τοῦ θεοῦ τὰ διεσκορπισμένα συναγάγῃ εἰς ἕν</strong> — "and not only on behalf of the nation, but also that he might gather together the scattered children of God into one." The Evangelist expands Caiaphas\'s prophecy beyond its stated scope: the death is not merely for Israel but for <em>ta tekna tou theou ta dieskorpismena</em> — "the scattered children of God." <em>Diaskorpizō</em> (G1287, perfect passive participle) — "scattered/dispersed" — the same root as in 10:12 where the wolf scatters (<em>diaskorpizei</em>) the sheep. The good shepherd who lays down his life for the scattered sheep (10:15–16) gathers them into one flock. The dying and the gathering are the two sides of the same act. <em>Eis hen</em> — "into one" — a single unity, the same <em>hen</em> of 10:30 and 17:21–23.</p>',

    "53": '<p><strong>ἀπ᾽ ἐκείνης οὖν τῆς ἡμέρας ἐβουλεύσαντο ἵνα ἀποκτείνωσιν αὐτόν</strong> — "from that day therefore they plotted that they might kill him." <em>Bouleuō</em> (G4823, aorist middle) — to deliberate, take counsel, plan. The aorist marks the beginning of a settled decision. <em>Hina apokteinōsin</em> (purpose clause, G615, aorist subjunctive) — the goal of their deliberation is his death. The sign that raised a dead man becomes the catalyst for the plot to kill him. The irony is structural: the chapter that climaxes with the reversal of death ends with the decision to bring death. The raising of Lazarus and the plotting against Jesus belong to the same moment.</p>',

    "54": '<p><strong>Ἰησοῦς οὖν οὐκέτι παρρησίᾳ περιεπάτει ἐν τοῖς Ἰουδαίοις</strong> — "Jesus therefore no longer walked openly among the Jews." <em>Parrēsia</em> (G3954, boldness, openness) — the word Martha used of Lazarus\'s hope (v24), the word the disciples asked for (16:25). Public, open movement is over. <strong>ἀπῆλθεν εἰς τὴν χώραν ἐγγὺς τῆς ἐρήμου, εἰς Ἐφραὶμ λεγομένην πόλιν</strong> — "he went away to the region near the wilderness, to a town called Ephraim." <em>Erēmos</em> (G2048) — the wilderness, a recurrent site of divine withdrawal and preparation in biblical narrative. <strong>κἀκεῖ ἔμενεν μετὰ τῶν μαθητῶν</strong> — "and he stayed there with the disciples." <em>Meno</em> (G3306) — the purposeful dwelling verb again. The time until Passover is spent in deliberate obscurity.</p>',

    "55": '<p><strong>ἦν δὲ ἐγγὺς τὸ πάσχα τῶν Ἰουδαίων</strong> — "now the Passover of the Jews was near." The Evangelist marks the third Passover in the Gospel (cf. 2:13; 6:4) with this formula. <strong>ἀνέβησαν πολλοὶ εἰς Ἱεροσόλυμα ἐκ τῆς χώρας πρὸ τοῦ πάσχα</strong> — "many went up to Jerusalem from the country before the Passover." The verb <em>anabainō</em> (G305, to go up) is the standard idiom for the pilgrimage journey to Jerusalem, which is elevated geography. The purpose given — <strong>ἵνα ἁγνίσωσιν ἑαυτούς</strong> — "to purify themselves" — specifies the pre-festival purification requirement. Pilgrims who had contracted ritual impurity during travel needed to undergo purification before participating in Passover. The Evangelist is setting the stage: pilgrims are gathered, purification is underway, the festival that will become the frame for Jesus\'s death is approaching.</p>',

    "56": '<p><strong>ἐζήτουν οὖν τὸν Ἰησοῦν καὶ ἔλεγον μετ᾽ ἀλλήλων ἐν τῷ ἱερῷ ἑστηκότες</strong> — "they were seeking Jesus and saying to one another as they stood in the temple." The imperfect <em>ezētoun</em> and <em>elegon</em> — ongoing action, repeated conversation. The crowd standing in the temple courts are actively looking for him and debating among themselves. <strong>τί δοκεῖ ὑμῖν; ὅτι οὐ μὴ ἔλθῃ εἰς τὴν ἑορτήν;</strong> — "What do you think? That he will certainly not come to the festival?" The double negative <em>ou mē eltēi</em> (G3756 + G3361, aorist subjunctive) used as a question: "you don\'t think he\'s really going to show up, do you?" The crowd\'s uncertainty reflects their awareness that the authorities are looking for him — and yet they also want to see him, evidenced by their looking.</p>',

    "57": '<p><strong>δεδώκεισαν δὲ οἱ ἀρχιερεῖς καὶ οἱ Φαρισαῖοι ἐντολάς</strong> — "now the chief priests and the Pharisees had given orders." The pluperfect <em>dedōkeisan</em> (G1325) — "had given and the orders stood." The commands were prior to the festival gathering. <strong>ἵνα ἐάν τις γνῷ ποῦ ἐστιν μηνύσῃ</strong> — "that if anyone knew where he was, he should report it." <em>Mēnuō</em> (G3377) — to disclose, inform, report; sometimes used for informing on someone to the authorities. The mechanics of surveillance are put in place: the crowd is obligated to act as informants. The chapter ends with a crowd looking for Jesus in the temple, under orders to report him, while he is deliberately absent. The stage for chapters 12–19 is fully set.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', 'john')
    merge_comm(existing, JOHN)
    save_comm('mkt-original', 'john', existing)
    print('John 11 mkt-original written.')

if __name__ == '__main__':
    main()
